args.cypher:
MATCH (aas:AssetAdministrationShell)-[:HAS_SUBMODEL]->(sm:Submodel)
WHERE EXISTS {
  MATCH (aas)-[:HAS_SUBMODEL]->(sm2:Submodel)-[:HAS_ELEMENT*]->(e:SubmodelElement)
  WHERE e.idShort = 'Hall' AND EXISTS {
    MATCH (e)-[:HAS_VALUE]->(v:LangString) WHERE v.text CONTAINS 'Hall 4'
  }
}
RETURN aas.idShort, aas.id
LIMIT 10

MATCH (aas:AssetAdministrationShell)-[:HAS_SUBMODEL]->(sm:Submodel)
WHERE EXISTS {
  MATCH (aas)-[:MANAGES_ASSET]->(asset:Asset)
  WHERE asset.globalAssetId CONTAINS 'hall4' OR asset.globalAssetId CONTAINS 'hall 4' OR aas.idShort CONTAINS 'hall4' OR aas.idShort CONTAINS 'hall 4'
}
RETURN aas.idShort, aas.id, sm.idShort, sm.id
